export function getPatientEarlyBodyLine(bodyType, attitude) {
  const tier = attitude === 'noticing' ? 'noticing' : 'professional';
  const lines = patientEarlyBody[bodyType] || patientEarlyBody.hourglass;
  return lines[tier];
}
